import React from "react";

const About = () => {
  return (
    <section id="about" className="py-20 px-6 max-w-5xl mx-auto">
      <h2 data-aos="fade-right" className="text-3xl font-bold text-center mb-8">About Me</h2>
      <p data-aos="fade-left" className="text-lg text-gray-700 dark:text-gray-200 leading-relaxed text-center">
        I’m Hetvi Prajapati, Computer Science student with hands-on experience in full-stack development, building APIs, 
        and deploying scalable solutions using Java, Python (Flask, .NET), React, SQL, Android Studio, and cloud platforms 
        (Azure, AWS). Skilled in backend systems, mobile and web app development, RESTful APIs, and cloud services. 
        Fast learner with a startup mindset, strong communication skills, and a proven ability to deliver in high-pressure, 
        cross-functional environments.
      </p>
    </section>
  );
};

export default About;
